import{_ as t,o as e,c as s,ag as n}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Crypto Namespace","description":"","frontmatter":{},"headers":[],"relativePath":"guide/crypto.md","filePath":"guide/crypto.md"}'),d={name:"guide/crypto.md"};function o(r,a,p,c,l,i){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="crypto-namespace" tabindex="-1">Crypto Namespace <a class="header-anchor" href="#crypto-namespace" aria-label="Permalink to &quot;Crypto Namespace&quot;">​</a></h1><p>The <code>Crypto</code> namespace provides hardware-accelerated cryptographic micro-helpers. These are single-instruction building blocks that the compiler maps to platform-specific intrinsics (x86 AES-NI / ARM Crypto Extensions) automatically.</p><blockquote><p><strong>No import needed.</strong> <code>Crypto.*</code> is a builtin namespace available everywhere.</p></blockquote><blockquote><p><strong>These are building blocks, not full algorithms.</strong> For complete crypto implementations (AES-256-GCM, SHA-256, ChaCha20, etc.), see the <a href="/docs/stdlib"><code>crypto</code> standard library package</a>.</p></blockquote><h2 id="quick-example" tabindex="-1">Quick Example <a class="header-anchor" href="#quick-example" aria-label="Permalink to &quot;Quick Example&quot;">​</a></h2><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// CRC-32C checksum of a byte array</span></span>
<span class="line"><span>fn crc32(data: &amp;[u8], len: usize): u32 {</span></span>
<span class="line"><span>    let! crc: u32 = 0xFFFFFFFF;</span></span>
<span class="line"><span>    let! i: usize = 0;</span></span>
<span class="line"><span>    while i &lt; len {</span></span>
<span class="line"><span>        crc = Crypto.crc32c(crc, data[i]);</span></span>
<span class="line"><span>        i = i + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return crc ^ 0xFFFFFFFF;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="aes-round-operations" tabindex="-1">AES Round Operations <a class="header-anchor" href="#aes-round-operations" aria-label="Permalink to &quot;AES Round Operations&quot;">​</a></h2><p>Single AES round instructions — the core building block of AES-128/192/256.</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Crypto.aesEncRound(state, key)</code></td><td><code>([u8;16], [u8;16]) → [u8;16]</code></td><td>SubBytes → ShiftRows → MixColumns → AddRoundKey</td></tr><tr><td><code>Crypto.aesDecRound(state, key)</code></td><td><code>([u8;16], [u8;16]) → [u8;16]</code></td><td>Inverse AES round</td></tr><tr><td><code>Crypto.aesEncLast(state, key)</code></td><td><code>([u8;16], [u8;16]) → [u8;16]</code></td><td>Final round (no MixColumns)</td></tr><tr><td><code>Crypto.aesDecLast(state, key)</code></td><td><code>([u8;16], [u8;16]) → [u8;16]</code></td><td>Final inverse round</td></tr></tbody></table><h3 id="platform-mapping" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Vex Function</th><th>x86 (AES-NI)</th><th>ARM (Crypto Ext.)</th></tr></thead><tbody><tr><td><code>aesEncRound</code></td><td><code>AESENC</code> (1 cycle)</td><td><code>AESE</code> + <code>AESMC</code> (2 cycles)</td></tr><tr><td><code>aesDecRound</code></td><td><code>AESDEC</code></td><td><code>AESD</code> + <code>AESIMC</code></td></tr><tr><td><code>aesEncLast</code></td><td><code>AESENCLAST</code></td><td><code>AESE</code></td></tr><tr><td><code>aesDecLast</code></td><td><code>AESDECLAST</code></td><td><code>AESD</code></td></tr></tbody></table><blockquote><p><strong>~500x faster</strong> than the pure Vex software implementation per round.</p></blockquote><h3 id="usage-aes-256-encrypt-block" tabindex="-1">Usage: AES-256 Encrypt Block <a class="header-anchor" href="#usage-aes-256-encrypt-block" aria-label="Permalink to &quot;Usage: AES-256 Encrypt Block&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn aes256EncryptHW(block: [u8;16], roundKeys: &amp;[[u8;16]; 15]): [u8;16] {</span></span>
<span class="line"><span>    // XOR initial round key</span></span>
<span class="line"><span>    let! state = xorBlocks(block, roundKeys[0]);</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Rounds 1-13</span></span>
<span class="line"><span>    let! r = 1;</span></span>
<span class="line"><span>    while r &lt;= 13 {</span></span>
<span class="line"><span>        state = Crypto.aesEncRound(state, roundKeys[r]);</span></span>
<span class="line"><span>        r = r + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // Final round (no MixColumns)</span></span>
<span class="line"><span>    state = Crypto.aesEncLast(state, roundKeys[14]);</span></span>
<span class="line"><span>    return state;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="sha-256-hardware-acceleration" tabindex="-1">SHA-256 Hardware Acceleration <a class="header-anchor" href="#sha-256-hardware-acceleration" aria-label="Permalink to &quot;SHA-256 Hardware Acceleration&quot;">​</a></h2><p>Single-instruction SHA-256 computation — replaces the 64-round loop in software SHA-256.</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Crypto.sha256H(state, msg, k)</code></td><td><code>([u32;4], [u32;4], [u32;4]) → [u32;4]</code></td><td>SHA-256 hash update (2 rounds)</td></tr><tr><td><code>Crypto.sha256Msg0(msg0, msg1)</code></td><td><code>([u32;4], [u32;4]) → [u32;4]</code></td><td>Message schedule σ₀</td></tr><tr><td><code>Crypto.sha256Msg1(msg, prev)</code></td><td><code>([u32;4], [u32;4]) → [u32;4]</code></td><td>Message schedule σ₁</td></tr></tbody></table><h3 id="platform-mapping-1" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping-1" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Vex Function</th><th>x86 (SHA-NI)</th><th>ARM (SHA2 Ext.)</th></tr></thead><tbody><tr><td><code>sha256H</code></td><td><code>SHA256RNDS2</code></td><td><code>SHA256H</code></td></tr><tr><td><code>sha256Msg0</code></td><td><code>SHA256MSG1</code></td><td><code>SHA256SU0</code></td></tr><tr><td><code>sha256Msg1</code></td><td><code>SHA256MSG2</code></td><td><code>SHA256SU1</code></td></tr></tbody></table><blockquote><p><strong>~20-50x faster</strong> than software SHA-256. Processes 2 rounds per instruction.</p></blockquote><h2 id="carry-less-multiply" tabindex="-1">Carry-Less Multiply <a class="header-anchor" href="#carry-less-multiply" aria-label="Permalink to &quot;Carry-Less Multiply&quot;">​</a></h2><p>64×64→128 bit polynomial multiplication — essential for GCM (GHASH) and CRC computations.</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Crypto.clmul(a, b)</code></td><td><code>(u64, u64) → [u64;2]</code></td><td>Carry-less multiply, result = <code>[lo, hi]</code></td></tr></tbody></table><h3 id="platform-mapping-2" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping-2" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>x86</th><th>ARM</th></tr></thead><tbody><tr><td><code>PCLMULQDQ</code> (1-3 cycles)</td><td><code>PMULL</code> (1-2 cycles)</td></tr></tbody></table><blockquote><p><strong>~200-300x faster</strong> than software GF(2¹²⁸) multiply. Replaces the 128-iteration bit-by-bit loop in GHASH.</p></blockquote><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// GF(2^128) multiply for GCM — single instruction!</span></span>
<span class="line"><span>let result = Crypto.clmul(a, b);</span></span>
<span class="line"><span>let lo = result[0];  // Lower 64 bits</span></span>
<span class="line"><span>let hi = result[1];  // Upper 64 bits</span></span></code></pre></div><h2 id="crc-32c" tabindex="-1">CRC-32C <a class="header-anchor" href="#crc-32c" aria-label="Permalink to &quot;CRC-32C&quot;">​</a></h2><p>Hardware-accelerated CRC-32C (Castagnoli polynomial) — used in networking (iSCSI, SCTP) and storage (Btrfs, ext4).</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Crypto.crc32c(crc, byte)</code></td><td><code>(u32, u8) → u32</code></td><td>Update CRC with one byte</td></tr></tbody></table><h3 id="platform-mapping-3" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping-3" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>x86</th><th>ARM</th></tr></thead><tbody><tr><td><code>CRC32</code> (SSE4.2, 1 cycle)</td><td><code>CRC32CB</code> (1 cycle)</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn checksumData(data: RawBuf, len: i64): u32 {</span></span>
<span class="line"><span>    let! crc: u32 = 0xFFFFFFFF;</span></span>
<span class="line"><span>    let! i: i64 = 0;</span></span>
<span class="line"><span>    while i &lt; len {</span></span>
<span class="line"><span>        crc = Crypto.crc32c(crc, data.load&lt;u8&gt;(i));</span></span>
<span class="line"><span>        i = i + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return crc ^ 0xFFFFFFFF;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="secure-random" tabindex="-1">Secure Random <a class="header-anchor" href="#secure-random" aria-label="Permalink to &quot;Secure Random&quot;">​</a></h2><p>Cryptographically secure random number generation using hardware entropy.</p><table tabindex="0"><thead><tr><th>Function</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>Crypto.secureRand()</code></td><td><code>→ u64</code></td><td>64-bit CSPRNG value</td></tr></tbody></table><h3 id="platform-mapping-4" tabindex="-1">Platform Mapping <a class="header-anchor" href="#platform-mapping-4" aria-label="Permalink to &quot;Platform Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>x86</th><th>ARM / macOS</th></tr></thead><tbody><tr><td><code>RDRAND</code> (HW RNG)</td><td><code>arc4random</code> (kernel CSPRNG)</td></tr></tbody></table><blockquote><p>For non-cryptographic randomness (games, simulations), use <a href="/docs/guide/math#random-numbers"><code>Math.random()</code></a> instead — it&#39;s faster.</p></blockquote><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn generateKey(): [u8; 32] {</span></span>
<span class="line"><span>    let! key = [0u8; 32];</span></span>
<span class="line"><span>    let! i = 0;</span></span>
<span class="line"><span>    while i &lt; 4 {</span></span>
<span class="line"><span>        let rand = Crypto.secureRand();</span></span>
<span class="line"><span>        // Store 8 bytes from each u64</span></span>
<span class="line"><span>        let rb = RawBuf.of(&amp;key as ptr);</span></span>
<span class="line"><span>        rb.store&lt;u64&gt;(i * 8, rand);</span></span>
<span class="line"><span>        i = i + 1;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return key;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="hardware-support" tabindex="-1">Hardware Support <a class="header-anchor" href="#hardware-support" aria-label="Permalink to &quot;Hardware Support&quot;">​</a></h2><p>All <code>Crypto.*</code> functions require hardware support. The compiler automatically selects the right instruction for the target architecture.</p><table tabindex="0"><thead><tr><th>Feature</th><th>x86</th><th>ARM</th><th>Apple Silicon</th></tr></thead><tbody><tr><td>AES rounds</td><td>AES-NI (2010+)</td><td>ARMv8 Crypto</td><td>✅ M1+</td></tr><tr><td>SHA-256</td><td>SHA-NI (2016+)</td><td>ARMv8 SHA2</td><td>✅ M1+</td></tr><tr><td>CLMUL</td><td>PCLMULQDQ (2010+)</td><td>PMULL (ARMv8)</td><td>✅ M1+</td></tr><tr><td>CRC-32C</td><td>SSE4.2 (2008+)</td><td>CRC32 (ARMv8.1+)</td><td>✅ M1+</td></tr><tr><td>Secure RNG</td><td>RDRAND (2012+)</td><td>arc4random</td><td>✅ Always</td></tr></tbody></table><blockquote><p><strong>If hardware is not available</strong>, the compiler will emit an error at compile time. Use the pure Vex implementations from <code>lib/std/crypto</code> as a portable fallback.</p></blockquote><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/math">Math Namespace</a> — Mathematical functions and constants</li><li><a href="/docs/guide/bit">Bit Namespace</a> — Parallel bit manipulation</li><li><a href="/docs/stdlib">Crypto Library</a> — Full crypto algorithms (AES-GCM, SHA-256, etc.)</li></ul>`,46)])])}const b=t(d,[["render",o]]);export{u as __pageData,b as default};
